#!/bin/bash
# ═══════════════════════════════════════════════════════════════
#  Population Genetics for Conservation — One-Shot Installer
#  Run: bash install_popgen.sh
#  Creates ~/population_genetics/ with all files ready to push
# ═══════════════════════════════════════════════════════════════
set -e
REPO="$HOME/population_genetics"
echo "🧬 Creating repo at $REPO"
mkdir -p "$REPO/assets/css" "$REPO/assets/js" "$REPO/assets/images" "$REPO/modules"
cd "$REPO"
echo "📁 Directories created"

echo "📝 Writing source files..."

# --- index.html ---
echo "  index.html"
echo "" | base64 -d > "$REPO/index.html"

# --- assets/css/style.css ---
echo "  assets/css/style.css"
echo "" | base64 -d > "$REPO/assets/css/style.css"

# --- assets/js/main.js ---
echo "  assets/js/main.js"
echo "" | base64 -d > "$REPO/assets/js/main.js"

# --- README.md ---
echo "  README.md"
echo "" | base64 -d > "$REPO/README.md"

# --- assets/images/01_marker_evolution.png ---
echo "  assets/images/01_marker_evolution.png"
echo "" | base64 -d > "$REPO/assets/images/01_marker_evolution.png"

# --- assets/images/02_kenya_parks_map.png ---
echo "  assets/images/02_kenya_parks_map.png"
echo "" | base64 -d > "$REPO/assets/images/02_kenya_parks_map.png"

# --- assets/images/03_fastq_explainer.png ---
echo "  assets/images/03_fastq_explainer.png"
echo "" | base64 -d > "$REPO/assets/images/03_fastq_explainer.png"

# --- assets/images/04_hardy_weinberg.png ---
echo "  assets/images/04_hardy_weinberg.png"
echo "" | base64 -d > "$REPO/assets/images/04_hardy_weinberg.png"

# --- assets/images/05_population_structure.png ---
echo "  assets/images/05_population_structure.png"
echo "" | base64 -d > "$REPO/assets/images/05_population_structure.png"

# --- assets/images/06_diversity_metrics.png ---
echo "  assets/images/06_diversity_metrics.png"
echo "" | base64 -d > "$REPO/assets/images/06_diversity_metrics.png"

# --- assets/images/07_selection_types.png ---
echo "  assets/images/07_selection_types.png"
echo "" | base64 -d > "$REPO/assets/images/07_selection_types.png"

# --- assets/images/08_psmc_demographic.png ---
echo "  assets/images/08_psmc_demographic.png"
echo "" | base64 -d > "$REPO/assets/images/08_psmc_demographic.png"

# --- assets/images/09_pipeline_workflow.png ---
echo "  assets/images/09_pipeline_workflow.png"
echo "" | base64 -d > "$REPO/assets/images/09_pipeline_workflow.png"

# --- assets/images/10_tajimas_d.png ---
echo "  assets/images/10_tajimas_d.png"
echo "" | base64 -d > "$REPO/assets/images/10_tajimas_d.png"

echo "✅ All files written!"

cd "$REPO"

echo ""
echo "🔧 Initialising git..."
git init
git add .
git commit -m "🧬 Wildlife Genomics 3 — Population Genetics tutorial

Interactive tutorial with:
- 9 learning modules (Linux → Selection)
- 10 scientific figures (Kenya-specific)
- 12 clickable discussion questions with answers
- 8 Kenya wildlife case studies
- Full bioinformatics pipeline code
- Based on Hedrick Genetics of Populations 4th ed."

echo ""
echo "🔗 Adding remote and pushing..."
git branch -M main
git remote add origin https://github.com/Rodneyomukuti/population_genetics.git
git push -u origin main

echo ""
echo "════════════════════════════════════════════════════"
echo "✅  DONE! Repository pushed to GitHub."
echo ""
echo "🌐  Enable GitHub Pages:"
echo "    1. https://github.com/Rodneyomukuti/population_genetics/settings/pages"
echo "    2. Source → Deploy from branch → main → / (root) → Save"
echo "    3. Site live in ~60s at:"
echo "       https://Rodneyomukuti.github.io/population_genetics"
echo "════════════════════════════════════════════════════"
